+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -1257,7 +1257,7 @@ Instruction *InstCombinerImpl::foldICmpWithZero(ICmpInst &Cmp) {
   //   icmp eq/ne (urem %x, %y), 0
   // Iff %x has 0 or 1 bits set, and %y has at least 2 bits set, omit 'urem':
   //   icmp eq/ne %x, 0
-  Value *X, *Y;
+  Value *X, *Y, *Z;
   if (match(Cmp.getOperand(0), m_URem(m_Value(X), m_Value(Y))) &&
       ICmpInst::isEquality(Pred)) {
     KnownBits XKnown = computeKnownBits(X, 0, &Cmp);
@@ -3305,7 +3305,7 @@ Instruction *InstCombinerImpl::foldICmpInstWithConstant(ICmpInst &Cmp) {
     // (extractval ([s/u]subo X, Y), 0) != 0 --> X != Y
     // TODO: This checks one-use, but that is not strictly necessary.
     Value *Cmp0 = Cmp.getOperand(0);
-    Value *X, *Y;
+    Value *X, *Y, *Z;
     if (C->isZero() && Cmp.isEquality() && Cmp0->hasOneUse() &&
         (match(Cmp0,
                m_ExtractValue<0>(m_Intrinsic<Intrinsic::ssub_with_overflow>(
@@ -4346,7 +4346,7 @@ foldShiftIntoShiftInAnotherHandOfAndInICmp(ICmpInst &I, const SimplifyQuery SQ,
 /// will mean that we are looking for the opposite answer.
 Value *InstCombinerImpl::foldMultiplicationOverflowCheck(ICmpInst &I) {
   ICmpInst::Predicate Pred;
-  Value *X, *Y;
+  Value *X, *Y, *Z;
   Instruction *Mul;
   Instruction *Div;
   bool NeedNegation;
@@ -4519,6 +4519,10 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
   if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
     return nullptr;

+  // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
+  // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
+  // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
+  // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
   // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
   // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
   // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
@@ -4528,10 +4532,31 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // (~X ^ Y) cmp ~X --> (X ^ Y) swapped_cmp X
+  // where ~X = xor X, -1
+  // This works because ~A cmp ~B is equivalent to A swapped_cmp B for
+  // signed comparisons, and ~X ^ Y = ~(X ^ Y).
+  Value *XBase;
+  const APInt *C;
+  if (match(Op1, m_c_Xor(m_Value(XBase), m_APInt(C))) && C->isAllOnes()) {
+    // Op1 is ~X, Op0 is ~X ^ A
+    // Transform to: (X ^ A) swapped_cmp X
+    CmpInst::Predicate NewPred;
+    if (ICmpInst::isSigned(Pred)) {
+      // For signed comparisons, swap the predicate
+      NewPred = ICmpInst::getSwappedPredicate(Pred);
+    } else if (ICmpInst::isEquality(Pred)) {
+      // For equality, predicate stays the same
+      NewPred = Pred;
+    } else {
+      // For unsigned comparisons, the transformation doesn't hold
+      return nullptr;
+    }
+    return new ICmpInst(NewPred, IC.Builder.CreateXor(XBase, A), XBase);
+  }
+
   return nullptr;
 }
-
-/// Try to fold icmp (binop), X or icmp X, (binop).
 /// TODO: A large part of this logic is duplicated in InstSimplify's
 /// simplifyICmpWithBinOp(). We should be able to share that and avoid the code
 /// duplication.
@@ -5306,7 +5331,7 @@ Instruction *InstCombinerImpl::foldICmpEquality(ICmpInst &I) {
   {
     // Similar to above, but specialized for constant because invert is needed:
     // (X | C) == (Y | C) --> (X ^ Y) & ~C == 0
-    Value *X, *Y;
+    Value *X, *Y, *Z;
     Constant *C;
     if (match(Op0, m_OneUse(m_Or(m_Value(X), m_Constant(C)))) &&
         match(Op1, m_OneUse(m_Or(m_Value(Y), m_Specific(C))))) {
@@ -6337,7 +6362,7 @@ Instruction *InstCombinerImpl::foldICmpUsingKnownBits(ICmpInst &I) {
 /// If one operand of an icmp is effectively a bool (value range of {0,1}),
 /// then try to reduce patterns based on that limit.
 Instruction *InstCombinerImpl::foldICmpUsingBoolRange(ICmpInst &I) {
-  Value *X, *Y;
+  Value *X, *Y, *Z;
   ICmpInst::Predicate Pred;

   // X must be 0 and bool must be true for "ULT":
@@ -6617,7 +6642,7 @@ static Instruction *canonicalizeICmpBool(ICmpInst &I,
 static Instruction *foldICmpWithHighBitMask(ICmpInst &Cmp,
                                             InstCombiner::BuilderTy &Builder) {
   ICmpInst::Predicate Pred, NewPred;
-  Value *X, *Y;
+  Value *X, *Y, *Z;
   if (match(&Cmp,
             m_c_ICmp(Pred, m_OneUse(m_Shl(m_One(), m_Value(Y))), m_Value(X)))) {
     switch (Pred) {
@@ -7009,7 +7034,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
     return Res;

   {
-    Value *X, *Y;
+    Value *X, *Y, *Z;
     // Transform (X & ~Y) == 0 --> (X & Y) != 0
     // and       (X & ~Y) != 0 --> (X & Y) == 0
     // if A is a power of 2.
@@ -7031,6 +7056,18 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
                             ConstantInt::get(Op1->getType(), ~(*C)));
     }

+    // (~X ^ Y) cmp ~Z --> (X ^ Y) cmp' Z (where cmp' is the swapped predicate)
+    // This handles patterns like: (~a ^ b) slt ~z --> (a ^ b) sgt z
+    // X, Y already declared above
+    if (match(Op1, m_Not(m_Value(Z))) &&
+        match(Op0, m_c_Xor(m_Not(m_Value(X)), m_Value(Y)))) {
+      // Require at least one use to avoid code bloat
+      if (Op0->hasOneUse() || Op1->hasOneUse()) {
+        return new ICmpInst(I.getSwappedPredicate(),
+                            Builder.CreateXor(X, Y), Z);
+      }
+    }
+
     Instruction *AddI = nullptr;
     if (match(&I, m_UAddWithOverflow(m_Value(X), m_Value(Y),
                                      m_Instruction(AddI))) &&
@@ -7595,7 +7632,7 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   }

   // fcmp pred (fneg X), (fneg Y) -> fcmp swap(pred) X, Y
-  Value *X, *Y;
+  Value *X, *Y, *Z;
   if (match(Op0, m_FNeg(m_Value(X))) && match(Op1, m_FNeg(m_Value(Y))))
     return new FCmpInst(I.getSwappedPredicate(), X, Y, "", &I);

