      // For signed comparisons, swap the predicate
      NewPred = ICmpInst::getSwappedPredicate(Pred);
    } else if (ICmpInst::isEquality(Pred)) {
      // For equality, predicate stays the same
      NewPred = Pred;
    } else {
      // For unsigned comparisons, the transformation doesn't hold
      return nullptr;
    }
    return new ICmpInst(NewPred, IC.Builder.CreateXor(X, A), X);
  }

